<template>
  <div class="Labs">
    <div class="container mt-5 mb-5">
      <!-- header -->
      <div class="row pt-5 pb-5 text-left">
        <div class="col-md-7">
          <h3>
            <b>Your Lab Results</b>
          </h3>
        </div>
      </div>

      <!-- current labs -->
      <div v-if="loading" class="w-100 text-center mt-5">
        <b-spinner variant="info" style="width: 3rem; height: 3rem;" type="grow" label="Spinning"></b-spinner>
      </div>
      <div class="row m-0" v-else>
        <div v-for="(lab, i) in Labs" :key="i" class="col-md-6 mb-3">
          <LabTile class="shadow-sm" :lab="lab" />
        </div>
      </div>
      <div v-if="Labs.length === 0">
        <h6>No labs to display</h6>
      </div>
    </div>
  </div>
</template>

<script>
import LabTile from "@/components/LabTile";
import http from "@/network/Base.js";
import { mapState } from "vuex";

export default {
  name: "labs",
  components: {
    LabTile,
  },
  data() {
    return {
      Labs: [],
      loading: false,
    };
  },
  methods: {
    goBack() {
      this.$router.go(-1);
    },
    getLabs() {
      this.loading = true;
      http()
        .get(`/visits/diagnosticreport?patientId=${this.userInfo.szpatientid}`)
        .then(({ data }) => {
          // this.LabsCount = data.count;
          this.Labs = data.result.reverse();
        })
        .catch((error) => {
          this.loading = false;
          console.log(error);
          // this.$snotify.error('Sorry, cannot get Service detail')
        })
        .finally(() => {
          this.loading = false;
        });
    },
  },
  created() {
    this.getLabs();
  },
  computed: {
    ...mapState({
      userInfo: (state) => state.authStore.userInfo,
    }),
  },
};
</script>

<style scoped>
.Labs {
  width: 100%;
  overflow: hidden;
}
</style>
