            {{ upcomingCount }}
            upcoming appointment(s)
          </div>
          <!--<div
            v-else-if="upcomingCount <= 0 && !loading"
            class="col"
          >You have no upcoming appointment(s)</div>-->
        </div>
        <div class="row pt-4 mb-5">
          <div class="col-6 text-left">
            <button
              class="btn btn-sm btn-primary dropdown-toggle"
